const TRANSITIONS = {
    NONE: ['BUY_SUBMITTED', 'REDEEM_SUBMITTED', 'SWITCH_STEP1_SUBMITTED'],
    BUY_SUBMITTED: ['BUY_PENDING_CONFIRM', 'FAILED', 'MANUAL_RECON_REQUIRED'],
    BUY_PENDING_CONFIRM: ['BUY_CONFIRMED', 'FAILED', 'MANUAL_RECON_REQUIRED'],
    BUY_CONFIRMED: ['DONE', 'MANUAL_RECON_REQUIRED'],
    REDEEM_SUBMITTED: ['REDEEM_PENDING_CONFIRM', 'FAILED', 'MANUAL_RECON_REQUIRED'],
    REDEEM_PENDING_CONFIRM: ['CASH_PENDING_ARRIVAL', 'FAILED', 'MANUAL_RECON_REQUIRED'],
    CASH_PENDING_ARRIVAL: ['CASH_ARRIVED', 'FAILED', 'MANUAL_RECON_REQUIRED'],
    CASH_ARRIVED: ['DONE', 'SWITCH_STEP2_SUBMITTED', 'MANUAL_RECON_REQUIRED'],
    SWITCH_STEP1_SUBMITTED: ['SWITCH_STEP1_CONFIRMED', 'FAILED', 'MANUAL_RECON_REQUIRED'],
    SWITCH_STEP1_CONFIRMED: ['CASH_PENDING_ARRIVAL', 'FAILED', 'MANUAL_RECON_REQUIRED'],
    SWITCH_STEP2_SUBMITTED: ['SWITCH_STEP2_CONFIRMED', 'FAILED', 'MANUAL_RECON_REQUIRED'],
    SWITCH_STEP2_CONFIRMED: ['DONE', 'MANUAL_RECON_REQUIRED'],
    DONE: [],
    FAILED: [],
    MANUAL_RECON_REQUIRED: ['NONE']
};
export function canTransitionTrade(from, to) {
    return TRANSITIONS[from].includes(to);
}
